1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote (base premiums)", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 (only processing fee)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, { items: [] }, 0).premium).toBe(5);
8	  });
9	
10	  // Single main item base premiums (+ fee, no other modifiers; newcomer 0 years would add first-insurance — so use these as base-premium building blocks via the integration examples instead)
11	  it.todo("single sword base premium 100");
12	  it.todo("single amulet base premium 60");
13	  it.todo("single staff base premium 80");
14	  it.todo("single potion base premium 40");
15	
16	  // Components
17	  it.todo("single rune base premium 25");
18	  it.todo("single moonstone base premium 25");
19	
20	  // Building block of 3 alike components
21	  it.todo("2 runes → 50 base premium (no block)");
22	  it.todo("3 runes → 60 base premium (block applies)");
23	  it.todo("4 runes → 100 base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 175 base premium");
25	
26	  // "Alike" components
27	  it.todo("2 runes + 1 moonstone → 75 base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 base premium (two separate blocks)");
29	});
30	
31	describe("MHPCO Claim Office — quote (premium modifiers)", () => {
32	  // Item-specific modifiers and policy scope
33	  it.todo("cursed sword + plain amulet → policy base 160, curse adds 50 → 210 before further modifiers and fee");
34	
35	  // Modifier thresholds
36	  it.todo("customer with exactly 2 years → loyalty discount applies");
37	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
38	  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
39	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
40	
41	  // Rounding
42	  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");
43	});
44	
45	describe("MHPCO Claim Office — quote (integration examples)", () => {
46	  it.todo("newcomer cursed sword (steel, ench 3), 0 years → premium 165");
47	  it.todo("long-standing (3 yrs) 2nd contract, cursed sword (steel, ench 7) → premium 160");
48	});
49	
50	describe("MHPCO Claim Office — claim (standard reimbursement)", () => {
51	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400");
52	  it.todo("rune (value 250), damage 200 → payout 100");
53	});
54	
55	describe("MHPCO Claim Office — claim (special clauses)", () => {
56	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon clause only)");
57	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment clause only)");
58	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both clauses; 50% wins)");
59	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-enchantment clause applies at exactly 8)");
60	});
61	
62	describe("MHPCO Claim Office — claim (deductible per damage event)", () => {
63	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
64	  it.todo("two swords, dragon attack damages both → each entry own deductible");
65	  it.todo("more damage entries of a type than policy covers → claim rejected (error)");
66	});
67	
68	describe("MHPCO Claim Office — claim (cap)", () => {
69	  it.todo("sword cap 2000; claim 1500 → payout 1400, remainingCap 600");
70	  it.todo("sword cap 2000; two claims 1500 each → first payout 1400 rem 600, second payout 600 rem 0");
